css:
/* Palette */
--ink:        #18181a;
--ink-2:      #3a3a40;
--ink-3:      #6b6b75;
--ink-4:      #9b9ba6;
--bg:         #faf8f3;
--bg-2:       #f2ede2;
--surface:    #ffffff;
--border:     #e4ddd1;

/* Brand colors */
--gold:       #c9961a;
--gold-lt:    #fdf5e0;
--gold-dk:    #9a7010;
--blue:       #1d3557;
--blue-lt:    #e8eef5;
--blue-md:    #457b9d;
--terra:      #a0410d;
--terra-lt:   #faeee8;
--teal:       #2a7a6f;
--teal-lt:    #e6f4f2;
--violet:     #5c3d8f;
--violet-lt:  #f0ebfa;
--green:      #2d6a4f;
--green-lt:   #eaf4ef;
--olive:      #6b7c45;
--olive-lt:   #f0f3e6;

/* Zone colors (for day cards) */
--zone-salento:  #a0410d;
--zone-taranto:  #1d3557;
--zone-costa:    #2a7a6f;
--zone-valle:    #6b7c45;
--zone-matera:   #5c3d8f;
--zone-nord:     #c9961a;
--zone-murgia:   #457b9d;

/* Typography */
--ff-serif: 'Playfair Display', 'Book Antiqua', Georgia, serif;
--ff-sans:  'Source Sans 3', -apple-system, 'Helvetica Neue', Arial, sans-serif;
--ff-mono:  'JetBrains Mono', 'Fira Code', monospace;

/* Spacing scale */
--sp-1: 0.25rem;
--sp-2: 0.5rem;
--sp-3: 0.75rem;
--sp-4: 1rem;
--sp-5: 1.5rem;
--sp-6: 2rem;
--sp-7: 3rem;
--sp-8: 4rem;

/* Radii */
--r-sm: 6px;
--r-md: 10px;
--r-lg: 16px;
--r-xl: 24px;

/* Shadows */
--sh-sm: 0 1px 3px rgba(0,0,0,.06), 0 1px 2px rgba(0,0,0,.04);
--sh-md: 0 4px 16px rgba(0,0,0,.08), 0 2px 6px rgba(0,0,0,.05);
--sh-lg: 0 8px 32px rgba(0,0,0,.10), 0 4px 12px rgba(0,0,0,.06);
--sh-xl: 0 16px 60px rgba(0,0,0,.12), 0 8px 20px rgba(0,0,0,.07);
